import { useState, useEffect, useRef } from "react";

/* ═══════════════════════════════════════════════════════
   SUPABASE CONFIG — replace with your own credentials
   1. Go to https://supabase.com → New project
   2. Settings → API → copy "Project URL" and "anon public" key
   3. Run the SQL setup in your Supabase SQL editor (see README)
═══════════════════════════════════════════════════════ */
const SUPABASE_URL = ""; // e.g. "https://xxxx.supabase.co"
const SUPABASE_KEY = ""; // your anon public key

/* ── Supabase sync helper ── */
const sb = {
  _enabled: () => SUPABASE_URL.length > 0 && SUPABASE_KEY.length > 0,
  _headers: () => ({
    "Content-Type": "application/json",
    "apikey": SUPABASE_KEY,
    "Authorization": "Bearer " + SUPABASE_KEY,
    "Prefer": "return=minimal",
  }),

  async insert(table, data) {
    if (!this._enabled()) return;
    try {
      await fetch(SUPABASE_URL + "/rest/v1/" + table, {
        method: "POST",
        headers: this._headers(),
        body: JSON.stringify(data),
      });
    } catch(e) { console.warn("Supabase sync failed:", e); }
  },

  async upsert(table, data, onConflict) {
    if (!this._enabled()) return;
    try {
      await fetch(SUPABASE_URL + "/rest/v1/" + table + "?on_conflict=" + onConflict, {
        method: "POST",
        headers: { ...this._headers(), "Prefer": "resolution=merge-duplicates,return=minimal" },
        body: JSON.stringify(data),
      });
    } catch(e) { console.warn("Supabase upsert failed:", e); }
  },
};

/* ── Device ID — stable anonymous identifier per browser ── */
/* ── Online status hook ── */
const useOnlineStatus = () => {
  const [online, setOnline] = useState(navigator.onLine);
  useEffect(() => {
    const on = () => setOnline(true);
    const off = () => setOnline(false);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
    return () => { window.removeEventListener("online", on); window.removeEventListener("offline", off); };
  }, []);
  return online;
};

const getDeviceId = () => {
  let id = localStorage.getItem("iForestier_device_id");
  if (!id) {
    id = "dev_" + Math.random().toString(36).slice(2) + Date.now().toString(36);
    localStorage.setItem("iForestier_device_id", id);
  }
  return id;
};

const BG = "data:image/jpeg;base64,";
const STORAGE_KEY = "iForestier_profile";
const HISTORY_KEY = "iForestier_history";

const fmt = (n, d = 3) => n.toLocaleString("fr-FR", { minimumFractionDigits: d, maximumFractionDigits: d });
const volCalc = (d, l) => Math.PI * (d / 200) ** 2 * l;

