/* ═══════════════════════════════════════
   SHARED INPUT
═══════════════════════════════════════ */
function IOSInput({ label, value, onChange, placeholder, type="text", unit, autoFocus }) {
  return (
    <div style={{ marginBottom: 1 }}>
      {label && <div style={{ fontFamily:"'SF Pro Display',-apple-system,sans-serif", fontSize:12, fontWeight:600, color:C.label, letterSpacing:"0.06em", textTransform:"uppercase", marginBottom:6, paddingLeft:4 }}>{label}</div>}
      <div style={{ position:"relative", ...card({ borderRadius:12 }), padding:"0" }}>
        <input
          autoFocus={autoFocus}
          type={type} value={value} onChange={e=>onChange(e.target.value)}
          placeholder={placeholder}
          style={{
            width:"100%", background:"transparent", border:"none",
            padding: unit ? "14px 52px 14px 16px" : "14px 16px",
            color:"#fff", fontFamily:"'SF Pro Display',-apple-system,sans-serif",
            fontSize:17, outline:"none",
          }}
        />
        {unit && <span style={{ position:"absolute", right:16, top:"50%", transform:"translateY(-50%)", color:C.label, fontSize:15, fontFamily:"'SF Pro Display',-apple-system,sans-serif", pointerEvents:"none" }}>{unit}</span>}
      </div>
    </div>
  );
}

